So, I want to create a async data holder in C++ which can be got only if it has been initialized asynchronously previously. If it has not been initialized, it will return the default value of the type. Is this sufficient?

template
class AsyncDataHolder {
 enum class Status { NOT\_INITIALIZED, INITIALIZING, INITIALIZED };

 std::function initializer\_;
 Status status\_{NOT\_INITIALIZED};

 mutable bthread::ConditionVariable cv\_;
 mutable bthread::Mutex mtx\_;
 T value\_;

public:
 AsyncDataHolder(std::function initializer) : initializer\_(initializer) {
 }

 void InitializeAsync() {
 {
 std::unique\_lock lock(mtx\_);
 status\_ = Status::INITIALIZING;
 }

 recall::runDetachedBthread([&]() {
 std::unique\_lock lock(mtx\_);
 value\_ = initializer\_();
 status\_ = Status::INITIALIZED;
 cv\_.notify\_all();
 });
 }

 const T& Get() const {
 {
 std::shared\_lock lock(mtx\_);
 if (status\_ == Status::NOT\_INITIALIZED) {
 return value\_;
 }
 }
 std::unique\_lock lock(mtx\_);
 while (status\_ != Status::INITIALIZED) {
 cv\_.wait(lock);
 }
 return value\_;
 }
};

